var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"카린 웡! 작전 브리핑을 준비하기 위해, 13시 정각에 도착하였습니다! 이에 신고합니다!","JPN":"カリン・ウォン！　ブリーフィングを準備するため、13時定刻に到着しましたことをご報告いたします！","ENG":"Karin Wong! Reporting for duty at 13:00! Ready for the mission briefing!","TWN":"報告！卡琳，13點準時抵達準備作戰簡報！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"……알고 있겠지, 소령. 사태는 일각을 다툰다.","JPN":"……わかっているだろうな、少佐。事態は一刻を争う。","ENG":"...I'm sure you're well aware, Major. There is not a moment to be lost.","TWN":"……你應該也知道，現在情況很嚴重，少校。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"예상보다 일찍 고치에서 깨어난 네피림을 막기 위해, 전 세계가 총력을 다해 시간을 벌어주고 있다.","JPN":"予想より早く繭から目覚めたネフィリムを止めるため、全世界が総力を挙げて時間を稼いでくれている。","ENG":"The Nephil came out of the cocoon earlier than expected, and the whole world is using all its resources to give us time to stop it.","TWN":"為要阻止比預期還要早從繭中甦醒的諾菲力，全世界都在拼命爭取時間。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그리고…….","JPN":"それに……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"네피림과의 지난 전투에서 큰 부상을 입었던 사령관님이……","JPN":"この前、ネフィリムとの戦闘で大怪我を負った司令官が……","ENG":"Our commander, who suffered a grave injury from the last battle with the Nephil...","TWN":"在上一次和諾菲力的戰鬥中身負重傷的司令官……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"오늘 새벽…… 명을 달리하셨다.","JPN":"今日の未明……亡くなられた。","ENG":"Last night, he... passed away.","TWN":"在今天淩晨……離世。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사령관님이…….","JPN":"司令官が……","ENG":"Commander...","TWN":"司令官……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"따라서…… 전시 상황이기에 특별한 인사조치 없이, 일시적으로 내가 사령관을 맡게 되었다.","JPN":"よって……戦時下のため特別な人事措置なしに、俺が臨時の司令官を引き受けることになった。","ENG":"Therefore... I've been assigned the temporary title of commander without any particular transfer, considering the fact that we are in times of war.","TWN":"……因為是戰時，所以在沒有特別人事調動的情況下，暫時由我擔任司令官。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이걸로…… 델타 세븐은 너와 나 둘 밖에 남지 않았군.","JPN":"これで……デルタセブンは俺とお前、二人だけになったな。","ENG":"This means... you and I are the only remaining members of Delta Seven.","TWN":"因此……第七三角洲部隊就只剩下你和我二個人。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하지만 긍지 높은 델타 세븐의 대원인 이상, 우리는 슬퍼하거나 망설일 겨를 따위 없다.","JPN":"だが誇り高きデルタセブンの隊員である以上、俺たちは悲しんだり、戸惑っている暇などない。","ENG":"However, as proud members of Delta Seven, we have no time to grieve or hesitate.","TWN":"但身為榮耀的第七三角洲部隊隊員，我們無暇為此悲傷或猶豫。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"지금 이 시각에도 수없이 사람이 죽어나가고 있다.","JPN":"今この時にも、数多くの人が死んでいる。","ENG":"Even at this very moment, people are dying.","TWN":"現在這一刻也有無數人正在死去。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"알고 있겠지, 소령. 우리는 그들을 구해야만 하는 의무가 있어.","JPN":"わかっているだろうな、少佐。俺たちは彼らを救う義務がある。","ENG":"I don't need to say it twice, do I, Major? Our duty is to save them.","TWN":"你明白吧，少校。我們有義務拯救他們。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네……! 알고 있습니다!","JPN":"はい……！　わかっています！","ENG":"Yes...! I am aware!","TWN":"是……！我明白！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"좋다, 소령. 그렇다면 이번 작전을 위해 계약한 용병들을 소개하겠다.","JPN":"よろしい、少佐。それでは、今度の作戦のために契約した傭兵たちを紹介しよう。","ENG":"Very well, Major. Then let me introduce the mercenaries we've hired for this operation.","TWN":"很好，少校，我替你介紹一下這次作戰我們特別雇用的傭兵。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"요, 용병……?","JPN":"よ、傭兵……？","ENG":"M-mercenaries...?","TWN":"傭，傭兵……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이야, 이거 영광이네요. 죽기전에 이렇게 말끔한 기지에서 미팅도 다 해보고.","JPN":"いやぁ、光栄です。死ぬ前にこんなキレイな基地でミーティングもできるなんて。","ENG":"Wow, what an honor, getting to attend a meeting at such a neat base before I die!","TWN":"哇，真是榮幸，沒想到死前能在這麼乾淨的基地參加會議。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이런 곳에서 편하게 일하는 분들이 참 부러운데요?","JPN":"こんなところで楽に働いてる人たちが本当にうらやましいですよ。","ENG":"I envy the people who get to work in such a luxurious environment.","TWN":"能在這種舒服的地方工作的人真令人羡慕呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"안 그래, 사이버 캣?","JPN":"そうじゃない？　サイバーキャット。","ENG":"Wouldn't you agree, Cyber Cat?","TWN":"對不對，賽博貓？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"시끄러워, 능구렁이. 누구는 좋아서 여기 온 줄 알아?","JPN":"うるさい、狸。アタシは来たくてここに来てるわけじゃないの。","ENG":"Shut it, Smirky. You think I like being here?","TWN":"少廢話，老油條。你以為我想來嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"너한테 뒤통수를 맡기게 될 줄 알았으면, 세상이 멸망한다고 해도 이딴 작전 받아들이지도 않았어.","JPN":"アンタに背中を任せることになるって知ってたら、世界が滅亡するとしてもこんな作戦、参加しなかったわ。","ENG":"If I knew I had to trust you with my life, I would've never joined this operation, even if it meant the end of the world.","TWN":"早知道要把我的命交給你這種人，就算是世界滅亡我也不會接受這種作戰。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"한쪽은 파렴치한 복장에…… 다른 쪽은 아직 어린애……?","JPN":"一人は破廉恥な服装に……もう一人はまだ子ども……？","ENG":"One's wearing some kind of vulgar outfit and... the other's a child...?","TWN":"一個穿著丟人的服裝……另一個居然是孩子……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이 사람들이……! 이번 작전 맴버……!?","JPN":"この人たちが……！　今度の作戦のメンバー……！？","ENG":"These people are my teammates for this operation?!","TWN":"這些人……！就是這次的作戰成員……？！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어머, 파렴치하다뇨. 섭섭하게…….","JPN":"あら、破廉恥だなんて。悲しいなぁ……","ENG":"Oh my, vulgar? I'm hurt.","TWN":"哎唷，什麼丟人，很傷我心的……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이래봬도 이 업계에서는 나름대로 잘 갖춰 입고 다니는 편이라구요?","JPN":"こう見えて、この業界ではそれなりにちゃんと着ている方なんですよ？","ENG":"I wear clothes more appropriately than most people who work in this field.","TWN":"你別看我穿成這樣，在這個行業裡我已經算是穿得比較正式的呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"흥, 나이로 사람을 평가하는 건 그다지 좋은 태도가 아닐 텐데, 카린 웡 소령.","JPN":"フン、年齢で人を評価するのはあまりいい態度じゃないわね、カリン・ウォン少佐。","ENG":"Hmph, you should know better than to judge people by their age, Major Karin Wong.","TWN":"哼，不要小看我年輕喔，卡琳少校。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어, 어떻게…… 내 이름을……?","JPN":"ど、どうやって……私の名前を……？","ENG":"H-how did you... know my name...?","TWN":"你，你怎麼會……知道我的名字……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"이름 뿐만이 아니야.","JPN":"名前だけじゃないわ。","ENG":"Not just your name.","TWN":"我知道的不僅你的名字。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"카운터 양성 계획의 마지막 기수에……. 첫 배속된 부서는 내사과 맞지?","JPN":"カウンター養成計画の最後の世代で……最初に配属された部署は内偵課よね？","ENG":"One of the last members to join the Counter training project, and... you were first assigned to the Internal Investigation Department, right?","TWN":"你還是制裁者培育計畫的最後一屆……一開始是被分配到內務科對不對？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이야, 여전히 기분나쁘게 사람 뒤 캐는 건 기가 막히게 잘하는 구나, 꼬맹이?","JPN":"いやぁ、相変わらず気持ち悪いくらい人の裏を暴くのがうまいね、おちびちゃん。","ENG":"Whoa, seems like you're still exceptionally skilled at digging through people's information, kiddo.","TWN":"哇，雖然不想承認，但你這個摸底細的本領依舊厲害呢，小不點。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"흥! 칼질이나 할 줄 아는 게 뭘 알겠어.","JPN":"フン！　刀を扱うことしかできないくせに。何もわかってないのね。","ENG":"Hmph! What would you know? You only swing your sword around.","TWN":"哼！只會舞刀弄槍的人懂什麼。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"미래에는 정보로 전쟁을 하는 시대가 올 거라고.","JPN":"未来には、情報で戦争をする時代が来るのよ。","ENG":"The future's gonna be all about information warfare.","TWN":"未來將會是情報戰的時代。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"미래? 그새 까먹었어? 사이버 캣?","JPN":"未来？　もう忘れちゃったの？　サイバーキャット。","ENG":"Future? Did you forget, Cyber Cat?","TWN":"未來？你忘記啦，賽博貓？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이 노란 머리 아저씨가 말한 작전을 실패하면 우리한테 미래는 없다구?","JPN":"この黄色い頭のおじさんが言ってた作戦に失敗したら、私たちに未来なんてないんだよ。","ENG":"There is no future if we fail at the mission that blondie was talking about.","TWN":"這個金毛大叔說，如果作戰失敗，我們就沒有未來咧！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대령님, 제가 감히 의문을 구해도 괜찮겠습니까?","JPN":"大佐、恐れながら質問をしてもよろしいでしょうか。","ENG":"Colonel, I apologize for my interruption, but I'd like to say a word.","TWN":"上校，我斗膽請教一個問題？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭐지?","JPN":"何だ？","ENG":"Yes?","TWN":"什麼問題？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"크로스로드 작전은 이 세상의 사활을 건 중대한 작전입니다!","JPN":"クロスロード作戦は、この世界の死活をかけた重要な作戦です！","ENG":"This world's very existence depends on Operation Crossroads. This operation is of the utmost importance!","TWN":"十字路口作戰是攸關這個世界生死存亡的重要作戰！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그런 중요한 작전에 이런 출신성분과 실력이 불분명한 자들을 고용하다니요!","JPN":"そのような重要な作戦に、このような出身階層も実力も不確かな者たちを雇うなんて！","ENG":"How could you hire individuals with unidentified backgrounds and capabilities in an operation that important?!","TWN":"在這種重要的時候，怎麼可以雇用這些來歷跟實力都不明的人呢！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"실력에 대해서는 검증이 끝났다.","JPN":"実力については検証済みだ。","ENG":"Their capabilities are already proven.","TWN":"我早已驗證過她們的實力。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"두 사람 모두 각자의 분야만큼은 최고라고 불러도 좋아.","JPN":"二人とも、各々の分野では最高と言ってもいい。","ENG":"You can consider them both at the top of their respective fields.","TWN":"這二個人在各自的領域可以說是最優秀的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하아, 이쪽 고용주님은 아직 세상 물정을 모르시네.","JPN":"はあ、こっちのクライアントは世間知らずだね。","ENG":"*Sigh* Our boss over here doesn't know how things work yet.","TWN":"哀，看來這位雇主的格局還不夠大呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭐라고요!?","JPN":"なんですって！？","ENG":"Excuse me?!","TWN":"你說什麼？！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이 노란 머리 아저씨가 말한 크로스핏인가 크로스로드인가……","JPN":"この黄色い頭のおじさんが言ってたクロスフィット？　クロスロード……？","ENG":"That crossfit or Crossroads or whatever that blondie was talking about...","TWN":"這個金毛大叔說的十字路口，還什麼的……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아무튼 그 작전이 망하면 우리 세계는 그대로 바이바이라면서요?","JPN":"とにかく、その作戦がダメになったら、私たちの世界はそのままバイバイって言ったじゃないですか。","ENG":"Our world is gonna go bye-bye if that operation fails, right?","TWN":"總之，如果那個作戰失敗，那我們的世界就玩完了對吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그런 와중에 출신이니, 뭐니…… 이런 거 따지는 거 보니 조금 실망인데요.","JPN":"なのに出身とか……そんなことを気にしてるなんて、ちょっとガッカリですね。","ENG":"And here you are, talking about backgrounds and stuff... I gotta say, I'm disappointed.","TWN":"這種情況下，你還計較來歷什麼的……真是令人有點失望呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"뭐, 우리 같은 용병나부랭이야, 보수만 받을 수 있다면 누구랑 일하던 상관없지만요.","JPN":"まあ、私たちのような傭兵は報酬さえもらえれば誰と働いても構わないんですけど。","ENG":"Well, for us mercenaries, we don't care who we work with as long as we get paid.","TWN":"像我們這種傭兵，只要能拿到報酬，為誰辦事都無所謂。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그만. 주시영의 말이 옳다, 소령.","JPN":"そこまで。アキヤマの言うとおりだ、少佐。","ENG":"Enough. Joo Shiyoung is right, Major.","TWN":"沒錯，周時雨說得對，少校。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"크로스로드 작전을 성공시킬 수만 있다면, 용병이든 민간인이든…… 수단을 가릴 때가 아니야.","JPN":"クロスロード作戦を成功させることさえできれば、傭兵でも民間人でも……手段を選んでいる場合じゃない。","ENG":"If we can lead Operation Crossroads to success, mercenary or civilian... we can't pick and choose.","TWN":"只要十字路口作戰能夠成功，不管是傭兵還是平民……我們都不該挑剔。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"미래를 위해 소령은 융통성을 좀 더 기르도록.","JPN":"未来のため、少佐はもっと融通性を身につけた方がよさそうだな。","ENG":"I expect you to be more flexible in the future, Major.","TWN":"為了世界的未來，希望少校能懂得變通。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네. 알겠습니다.","JPN":"はい。了解しました。","ENG":"Yes. Understood.","TWN":"是，我知道了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그럼, 지금부터 크로스로드 작전에 대해 브리핑하겠다.","JPN":"それでは、今からクロスロード作戦についてブリーフィングする。","ENG":"Now, I'll start the briefing on Operation Crossroads.","TWN":"現在，我來為大家說明作戰計畫。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사전에 고한대로 작전의 개요는 간단하다.","JPN":"事前に告知したとおり、作戦の概要は簡単だ。","ENG":"As I previously mentioned, the operation's outline is simple.","TWN":"正如事先告知的一樣，作戰內容很簡單。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"세계를 유린하는 네피림을 사람이 살지 않는 이면 세계에 처박아 격리시켜버린다. 이상.","JPN":"世界を蹂躙しているネフィリムを、人が住んでいない裏世界に送り、隔離する。以上だ。","ENG":"We shove the wretched Nephil into Counterside where no human resides. The end.","TWN":"我們需要將肆虐這個世界的諾菲力放逐到無人居住的異界，以上。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이야, 간단해서 좋네요.","JPN":"いやぁ、簡単でいいですね。","ENG":"Ayy, I like the simplicity.","TWN":"哇喔，簡潔有力，我喜歡！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"말처럼 그리 간단한 이야기가 아니라고요, 시영 씨.","JPN":"そう簡単な話ではありません、シノンさん。","ENG":"It's not as simple as you think, Shiyoung.","TWN":"事情沒這麼簡單，時雨。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우선, 누군가 고심도 다이브를 통해 이면세계로 통하는 차원 통로를 열어야 하고…….","JPN":"まず、誰かが高深度ダイブをして裏世界に通じる次元通路を開かないといけませんし……","ENG":"First, someone has to open a dimensional passage to Counterside through a hyperdepth Dive...","TWN":"首先，需要有人透過高深度躍入，打開通往異界的次元通道……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"동시에 누군가는 네피림을 차원 통로까지 유인해야 해요.","JPN":"同時に、誰かはネフィリムを次元通路までおびき寄せないといけません。","ENG":"Simultaneously, someone has to lure the Nephil to the dimensional passage.","TWN":"同時，還需要有人把諾菲力引到次元通道。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"또한 각 작전 간에 타이밍이 무척 중요하기 때문에 각 현장 간 지휘와 소통을 소통을 맡아줄 사람이 필요하겠죠.","JPN":"また、各作戦同士のタイミングがとても重要ですので、各現場での指揮と疎通を受け持ってくれる人が必要でしょうね。","ENG":"The timing of each mission is very important, and therefore we will need someone to lead and manage communications between each site.","TWN":"而且，各個作戰之間的時機非常重要，我們還需要一個可以指揮和溝通各個現場的人。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"와아, 카린 양은 요점 정리가 확실하시네요.","JPN":"わあ、カリンさんはきっちり整理してるんですね。","ENG":"Wow, Karin's very good at summarizing the whole thing.","TWN":"哇，卡琳小姐整理的重點簡潔扼要呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"좋아, 요점을 잘 파악하고 있군.","JPN":"よし、要点はしっかり把握できているな。","ENG":"Good, you understand the main points.","TWN":"很好，你有掌握到重點。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"감사합니다.","JPN":"ありがとうございます。","ENG":"Thank you.","TWN":"謝謝。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"그럼, 문제는 누가 어떤 역할을 맡느냐겠지.","JPN":"じゃあ、問題は誰がどんな役割を担当するかよね。","ENG":"Then, the next question is, who's going to do what?","TWN":"那麼現在問題就是，由誰擔任什麼樣的角色囉？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"어느 쪽도 쉽지 않은 임무지만…… 성공 확률을 올리고 싶으면 나는 현장에서 빼는 게 나을 것 같은데?","JPN":"どっちの任務も簡単じゃないけど……成功の確率を上げたかったら、アタシは現場から抜けた方が良さそうね。","ENG":"None of those tasks are going to be easy, but... I suggest you keep me out of the field for a higher success rate.","TWN":"這個任務無論哪個角色都不容易……如果想提高成功率，還是不要把我安排到現場比較好吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에잇, 치사하게 어리다고 이럴 때만 빠져나가긴.","JPN":"ええいっ、こんな時だけ年齢を理由に抜けるなんて、ズルいね。","ENG":"Hmph, NOW you use your age to get out of things?","TWN":"哇，這種時候就仗著年齡小的優勢，真卑鄙。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"누가 나보다 일찍 태어나래?","JPN":"誰がアタシより先に生まれろって言った？","ENG":"Not my fault that you were born earlier than me.","TWN":"誰叫你要比我早出生？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"소령. 주시영과 함께 <color=#ffd34c>패스파인더</color>가 되어 길을 열어라.","JPN":"少佐。アキヤマと共に<color=#ffd34c>パスファインダー</color>となって道を開け。","ENG":"Major. You and Joo Shiyoung will be the <color=#ffd34c>Pathfinders</color> and lead the way.","TWN":"少校，你和周時雨一起成為<color=#ffd34c>開拓者</color>，為我們開路吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네……? 제가 말입니까?","JPN":"はい……？　私がですか？","ENG":"Sorry...? Me?","TWN":"嗯……？我嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"착각하지 마라, 소령.","JPN":"勘違いするな、少佐。","ENG":"Do not be mistaken, Major.","TWN":"不要誤會，少校。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그저 사이버 캣의 말대로 성공 확률을 조금이라도 더 올리려는 거다.","JPN":"サイバーキャットの言うとおり、成功率を少しでも上げるためだ。","ENG":"As Cyber Cat said, we must do everything we can to increase the chances of success.","TWN":"就像賽博貓所說，是因為要盡可能提高成功率。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"네 꼼꼼한 성격과 분석 능력은 이면세계에 도착했을 때, 큰 도움이 되겠지.","JPN":"お前の几帳面な性格と分析能力は、裏世界に着いた時に大いに役立つだろう。","ENG":"Your meticulousness and analytic abilities will be of great help when you arrive in Counterside.","TWN":"你細膩的性格和分析能力在異界裡會有很大的幫助。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"운이 좋다면, 이면세계 현지에서 고순도 이터니움을 발견해 생환 가능성을 더 올릴 수도 있을 거다.","JPN":"運が良ければ、裏世界の現地で高純度のエタニウムを発見して、生還の可能性をもっと上げられるかもしれない。","ENG":"With luck, you might find high-purity Eternium in Counterside and increase your chances of coming back alive.","TWN":"如果運氣好，說不定還能在異界發現高純度永恆之金，提高生還的可能性。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"명심해라. 이 크로스로드 작전은 네가 있기 때문에 성립할 수 있는 것이다, 소령.","JPN":"肝に銘じておけ。このクロスロード作戦は、お前がいるから成立するんだ、少佐。","ENG":"Remember. Operation Crossroads is only feasible because of you, Major.","TWN":"記住，這個十字路口作戰是因為有你才能成立的，少校。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇지만…….","JPN":"ですが……","ENG":"But still...","TWN":"但是……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"제가 잘 할 수 있을까요……?","JPN":"私に上手くやれるでしょうか……？","ENG":"Will I be able to do it...?","TWN":"我可以嗎……？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"무슨 소리지? 잘 할 수 있겠냐고?","JPN":"何を言ってるんだ？　上手くやれるかって？","ENG":"What are you talking about? \\"Will you be able to do it?\\"","TWN":"這是什麼問題？！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"틀렸어. 잘 해야만 한다! 왜냐하면 그게 우리의 의무니까!","JPN":"違う。上手くやるんだ！　なぜなら、それが俺たちの任務だからだ！","ENG":"Incorrect. You MUST do it! That is our duty!","TWN":"聽著，你必須可以！因為那是我們的義務！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"약한 마음은 버려라, 소령!","JPN":"弱気になるな、少佐！","ENG":"Be strong, Major!","TWN":"收起你那軟弱的心態，少校！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"말 했을 텐데? 우리의 작전 성공을 기다리는 사람이 <color=#ffd34c>아직</color> 많이 있다고.","JPN":"言ったはずだ。俺たちの作戦が成功することを待っている人が<color=#ffd34c>まだ</color>たくさんいると。","ENG":"I already told you. There are <color=#ffd34c>still</color> many people who are waiting for us to succeed.","TWN":"我說過！<color=#ffd34c>仍有</color>很多人期盼著我們的成功！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네……! 죄송합니다. 대령님!","JPN":"はい……！　申し訳ありません、大佐！","ENG":"Of course...! My apologies, Colonel!","TWN":"是……！對不起，上校！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그리고 카린의 호위는 주시영이 맡도록.","JPN":"それから、カリンの護衛はアキヤマに任せる。","ENG":"Joo Shiyoung, you'll be tasked with escorting Karin.","TWN":"還有，周時雨負責掩護卡琳。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네이, 네이.","JPN":"はい、はい。","ENG":"Sure, sure.","TWN":"OKOK，沒問題。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아……! 저와의 계약은 잊지 않았겠죠, 노란 머리 아저씨?","JPN":"あ……！　私との契約、忘れてませんよね？　黄色い頭のおじさん？","ENG":"Oh...! You didn't forget our deal, did you, blondie?","TWN":"那個……！沒有忘記和我的約定吧，金毛大叔？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"사실, 부모님께는 아직 작전 참여한다고 말 안하고 왔거든요.","JPN":"実は、親にはまだ作戦に参加するって話してないんですよ。","ENG":"I actually didn't tell my parents that I was participating in this operation.","TWN":"其實，我還沒跟父母說我來參加作戰呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"물론이다. 이번 작전에만 성공한다면, 자네는 사람들에게 영웅으로 기억될 거다.","JPN":"もちろんだ。今度の作戦さえ成功すれば、君は英雄として記憶されるだろう。","ENG":"Of course. If you succeed in this operation, you'll be remembered as a hero.","TWN":"當然，只要這次作戰成功，你就會成為永垂青史的的英雄。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"자네의 부모에게는 군에서 제공할 수 있는 최고의 편의를 제공하지.","JPN":"君のご両親には軍から提供できる最高の便宜を提供しよう。","ENG":"I will provide your parents with the best accommodations the military can offer.","TWN":"軍隊也會盡可能照顧你的父母。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"마지막으로…… 네피림을 유인하는 역할은 내가 맡지.","JPN":"最後に……ネフィリムをおびき寄せる役割は俺が担当する。","ENG":"Lastly... I'll be the one to lure the Nephil.","TWN":"最後……引誘諾菲力的角色就由我來吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이중에 그나마 4종 침식체를 상대로 시간을 끌어 볼 수 있는 건 나 밖에 없을 것 같으니까.","JPN":"この中で第4種侵食体を相手に時間を稼げるのは、俺しかいないと思うからな。","ENG":"It seems like I'm the only one who could possibly stall a Category 4 C.O.","TWN":"畢竟在這些人裡，面對4級侵蝕體時能拖延時間的就只有我。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……대령님.","JPN":"……大佐。","ENG":"...Colonel.","TWN":"……上校。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"시뮬레이터로 네피림의 예상 경로를 예측한 결과, 네피림이 작전 구역에 도착하는 예정 시각은 일주일 뒤…….","JPN":"シミュレーターでネフィリムの経路を予測した結果、ネフィリムが作戦区域に到着する予定時刻は一週間後……","ENG":"We ran the simulator to predict the Nephil's route, and the Nephil is estimated to arrive at the operations area one week from now...","TWN":"用模擬器預測的路徑結果顯示，諾菲力到達作戰區域的時間大約在一週後……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그 일주일이 인류의 마지막이 될지…… 그렇지 않을지는 우리 델타 세븐의 손에 달려있다.","JPN":"その一週間が人類の最後になるか……ならないかは、俺たちデルタセブンにかかっている。","ENG":"Whether that one week is humanity's last week or not... is in Delta Seven's hands.","TWN":"那一週會不會成為人類的最後……就取決於我們第七三角洲部隊。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"작전 시작 전까지 모든 대원은 최상의 컨디션을 유지하도록…….","JPN":"作戦開始まで、全隊員は最高のコンディションを維持するように……","ENG":"I expect all members to maintain their best form until the operation starts.","TWN":"作戰開始前，希望所有隊員能保持最好的狀態……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이상!","JPN":"以上だ！","ENG":"Dismissed!","TWN":"以上！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"부르셨습니까! 대령님!","JPN":"お呼びでしょうか！　大佐！","ENG":"I heard you were looking for me, Colonel?","TWN":"找我嗎，上校！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"왔나, 소령.","JPN":"来たか、少佐。","ENG":"You're here, Major.","TWN":"你來啦，少校。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"크로스로드 작전을 시작하기 전에…… 소령에게 물려 줄 것이 있어서 불렀다.","JPN":"クロスロード作戦を開始する前に……少佐に渡したいものがあって呼んだんだ。","ENG":"I called you here because... I wanted to pass something on to you before Operation Crossroads started.","TWN":"我叫你來是因為……在十字路口作戰開始之前，有樣東西要給你。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"물려 줄 것……? 그게 무엇입니까?","JPN":"渡したいもの……？　何でしょうか。","ENG":"Pass something on...? What do you mean?","TWN":"有東西要給我……？是什麼？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이, 이건……?","JPN":"こ、これは……？","ENG":"Th-this is...","TWN":"這，這是……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"델타 세븐의 마스터 코드가 담겨있는 메모리 칩이다.","JPN":"デルタセブンのマスターコードが入っているメモリーチップだ。","ENG":"It's a memory chip that contains the master code for Delta Seven.","TWN":"這是裝著第七三角洲部隊管理代碼的記憶卡片。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그 코드가 있다면…… 긴급 작전 명령, <color=#ffd34c>프리덤 스트라이크</color>를 발동시킬 수 있겠지.","JPN":"そのコードがあれば……緊急作戦命令、<color=#ffd34c>フリーダムストライク</color>を発動させることができるだろう。","ENG":"With that code... you can commence the emergency operation order, <color=#ffd34c>Freedom Strike</color>.","TWN":"只要有這個代碼……就可以發動緊急作戰命令<color=#ffd34c>自由之擊</color>。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아쉽게도……. 델타 세븐의 남은 기함이라고 해봤자, 이젠 한 대뿐이지만 말이야.","JPN":"残念ながら……デルタセブンに残っている旗艦など、もう一隻しかないがな。","ENG":"Unfortunately... there's only one ship left in Delta Seven.","TWN":"可惜的是……第七三角洲部隊的繫船，就只剩下一艘。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이걸…… 왜 저에게…….","JPN":"これを……どうして私に……","ENG":"Why… would you give this to me...?","TWN":"為什麼……要給我這個……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사령관님이 돌아가시기 전에 내게 넘겨준 것이지만, 아무래도 나는 쓸 수 없을 것 같거든.","JPN":"司令官がお亡くなりになる前に託されたものだが、おそらく俺は使えないだろう。","ENG":"The chip was given to me by the commander before he passed away, but it doesn't seem like I'll be able to use it.","TWN":"司令官去世之前把這個東西留給我，但我很可能用不到。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"생환 가능성이 조금이라도 높은 소령이 갖고 있는 게 맞겠다 싶어서…….","JPN":"生還の可能性が少しでも高い少佐が持っていた方がいいと思ってな……","ENG":"I thought it was better for you to keep it since you have a higher chance of coming back alive...","TWN":"我覺得這個東西還是交給生還機率比我高一些的少校比較好……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대령님은……!!","JPN":"大佐は……！！","ENG":"Colonel...!","TWN":"上校……！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대령님은 두렵지 않으세요……!?","JPN":"大佐は怖くないのですか……！？","ENG":"Aren't you afraid...?!","TWN":"你不怕嗎……？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그, 그 네피림을…… 맨 몸으로 유인한다는 건…… 즉…….","JPN":"あ、あのネフィリムを……武装もせずおびき寄せるということは……つまり……","ENG":"L-luring that Nephil... on your own... means...","TWN":"赤手空拳……面對……諾菲力……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"...Ha ha.","TWN":"……哈哈。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"나라고 어째서 두렵지 않겠어?","JPN":"怖くないはずがない。","ENG":"Do you think I'm not terrified?","TWN":"你怎麼知道我不會害怕？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대령님?","JPN":"大佐？","ENG":"Colonel?","TWN":"上校？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하지만 그저 마지막 순간까지 포기하지 않고 최선을 다하고 싶을 뿐이야.","JPN":"だが、ただ最後の瞬間まで諦めず、全力を尽くしたいだけだ。","ENG":"I just want to do my best without giving up until it's over.","TWN":"但我只是想堅持到最後一刻，絕不放棄，盡力而為。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사령관님…… 그리고 먼저 간 다른 대원들 보기에 부끄럽지 않게 말이지.","JPN":"司令官……そして、先に逝った隊員たちに恥ずかしくないようにな。","ENG":"So I won't be ashamed to see the commander... and the rest of our fallen comrades.","TWN":"我希望能夠無愧於司令官……以及其他犧牲的隊員。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그러니까, 너도 긍지 높은 델타 세븐의 일원이라면…….","JPN":"だから、お前も誇り高きデルタセブンの一員であるなら……","ENG":"So, as a proud member of Delta Seven...","TWN":"所以，你若也是榮耀第七三角洲部隊的一員……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"마지막 순간까지 포기하지 마, 카린.","JPN":"最後の瞬間まであきらめるな、カリン。","ENG":"Don't give up until it's over, Karin.","TWN":"那就堅持到最後，不要放棄，卡琳。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네, 명심하겠습니다!!","JPN":"はい、肝に銘じます！！","ENG":"Yes, sir! I'll never forget it!","TWN":"是，我會記住的！！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"그리고…… 지금까지 존경했습니다, 대령님.","JPN":"それから……今まで尊敬していました、大佐。","ENG":"And... you've always had my respect, Colonel.","TWN":"另外……我一直很敬重你，上校。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};